public void testDrawWithNullDatasetAndLegend() {
    JFreeChart chart = ChartFactory.createPieChart3D("Test", null, true, 
            true, false);
    boolean success = false;
    try {
        BufferedImage image = new BufferedImage(200 , 100, 
                BufferedImage.TYPE_INT_RGB);
        Graphics2D g2 = image.createGraphics();
        chart.draw(g2, new Rectangle2D.Double(0, 0, 200, 100), null, null);
        g2.dispose();
        success = true;
    }
    catch (Exception e) {
        success = false;
    }
    assertTrue(success);
}

public void testGetMaximumExplodePercentWithNullDataset() {
    PiePlot3D plot = new PiePlot3D(null);
    double maxExplode = plot.getMaximumExplodePercent();
    assertEquals(0.0, maxExplode, 0.0001);
}
